import{_ as o,C as d,o as a,c as i,ah as e,b as h,w as r,a as n,E as s,ai as c}from"./chunks/framework.BxtGL5S5.js";const q=JSON.parse('{"title":"第10週：画像センサと計測","description":"","frontmatter":{},"headers":[],"relativePath":"weeks/week-10.md","filePath":"weeks/week-10.md","lastUpdated":1772094536000}'),b={name:"weeks/week-10.md"};function u(p,t,m,E,_,D){const l=d("Mermaid");return a(),i("div",null,[t[1]||(t[1]=e('<h1 id="第10週-画像センサと計測" tabindex="-1">第10週：画像センサと計測 <a class="header-anchor" href="#第10週-画像センサと計測" aria-label="Permalink to &quot;第10週：画像センサと計測&quot;">​</a></h1><blockquote><p>⏱️ 読了時間：約20分 | 📝 確認問題：5問</p></blockquote><h2 id="学習目標" tabindex="-1">学習目標 <a class="header-anchor" href="#学習目標" aria-label="Permalink to &quot;学習目標&quot;">​</a></h2><p>この週の講義を終えると、以下のことができるようになります：</p><ul><li>[ ] 距離画像（Depth Image）の取得方法を説明できる</li><li>[ ] RGB-Dカメラの概念を理解できる</li><li>[ ] 点群（Point Cloud）データの意味を説明できる</li><li>[ ] 画像計測の課題と限界を理解できる</li><li>[ ] 画像センサの応用事例を説明できる</li></ul><hr><h2 id="_1-距離画像-depth-image" tabindex="-1">1. 距離画像（Depth Image） <a class="header-anchor" href="#_1-距離画像-depth-image" aria-label="Permalink to &quot;1. 距離画像（Depth Image）&quot;">​</a></h2><h3 id="_1-1-距離画像とは" tabindex="-1">1.1 距離画像とは <a class="header-anchor" href="#_1-1-距離画像とは" aria-label="Permalink to &quot;1.1 距離画像とは&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">定義</p><p><strong>距離画像</strong>：各ピクセルに対象物までの距離情報を持つ画像。通常の画像（色情報）に加えて、奥行き情報を取得できます。</p></div><p>距離画像を取得する方法は、第9週で学んだ以下の原理に基づいています：</p><table tabindex="0"><thead><tr><th>方式</th><th>原理</th><th>特徴</th></tr></thead><tbody><tr><td><strong>ToF</strong></td><td>光の往復時間</td><td>高精度、屋外対応</td></tr><tr><td><strong>構造化光</strong></td><td>パターンの歪み</td><td>室内向き、高解像度</td></tr><tr><td><strong>ステレオカメラ</strong></td><td>視差（disparity）</td><td>パッシブ、長距離対応</td></tr></tbody></table><h3 id="_1-2-rgb-dカメラ" tabindex="-1">1.2 RGB-Dカメラ <a class="header-anchor" href="#_1-2-rgb-dカメラ" aria-label="Permalink to &quot;1.2 RGB-Dカメラ&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">定義</p><p><strong>RGB-Dカメラ</strong>：通常のカラー画像（RGB）と距離画像（Depth）を<strong>同時に</strong>取得できるカメラ。</p></div><table tabindex="0"><thead><tr><th>デバイス</th><th>方式</th><th>主な用途</th></tr></thead><tbody><tr><td>Microsoft Kinect</td><td>構造化光 / ToF</td><td>ゲーム、研究</td></tr><tr><td>Intel RealSense</td><td>構造化光 / ステレオ</td><td>組込み、ロボット</td></tr><tr><td>Stereolabs ZED</td><td>ステレオカメラ</td><td>自動運転、ドローン</td></tr><tr><td>Leap Motion</td><td>赤外線ステレオ</td><td>ハンドトラッキング</td></tr></tbody></table><hr><h2 id="_2-点群-point-cloud" tabindex="-1">2. 点群（Point Cloud） <a class="header-anchor" href="#_2-点群-point-cloud" aria-label="Permalink to &quot;2. 点群（Point Cloud）&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">定義</p><p><strong>点群</strong>：距離画像の各ピクセルに対応する<strong>3D座標データ</strong>の集合。</p></div>',17)),(a(),h(c,null,{default:r(()=>[s(l,{id:"mermaid-184",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%22RGB-D%E3%82%AB%E3%83%A1%E3%83%A9%22%5D%20--%3E%20B%5B%22RGB%E7%94%BB%E5%83%8F%3Cbr%3E%EF%BC%88%E8%89%B2%E6%83%85%E5%A0%B1%EF%BC%89%22%5D%0A%20%20%20%20A%20--%3E%20C%5B%22Depth%E7%94%BB%E5%83%8F%3Cbr%3E%EF%BC%88%E8%B7%9D%E9%9B%A2%E6%83%85%E5%A0%B1%EF%BC%89%22%5D%0A%20%20%20%20B%20--%3E%20D%5B%22%E7%82%B9%E7%BE%A4%E3%83%87%E3%83%BC%E3%82%BF%3Cbr%3E%EF%BC%883D%E5%BA%A7%E6%A8%99%20%2B%20%E8%89%B2%EF%BC%89%22%5D%0A%20%20%20%20C%20--%3E%20D%0A%20%20%20%20D%20--%3E%20E%5B%223D%E7%89%A9%E4%BD%93%E8%AA%8D%E8%AD%98%22%5D%0A%20%20%20%20D%20--%3E%20F%5B%22SLAM%22%5D%0A%20%20%20%20D%20--%3E%20G%5B%223D%E3%83%A2%E3%83%87%E3%83%AB%E7%94%9F%E6%88%90%22%5D%0A%20%20%20%20style%20A%20fill%3A%23E3F2FD%2Ccolor%3A%23333%0A%20%20%20%20style%20D%20fill%3A%23FFF3E0%2Ccolor%3A%23333%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e('<hr><h2 id="_3-画像計測の課題" tabindex="-1">3. 画像計測の課題 <a class="header-anchor" href="#_3-画像計測の課題" aria-label="Permalink to &quot;3. 画像計測の課題&quot;">​</a></h2><h3 id="_3-1-光学計測の課題" tabindex="-1">3.1 光学計測の課題 <a class="header-anchor" href="#_3-1-光学計測の課題" aria-label="Permalink to &quot;3.1 光学計測の課題&quot;">​</a></h3><table tabindex="0"><thead><tr><th>課題</th><th>説明</th><th>対策</th></tr></thead><tbody><tr><td><strong>非反射物体</strong></td><td>透明・黒色物体は反射が弱い</td><td>複数方式の併用</td></tr><tr><td><strong>屋外利用</strong></td><td>太陽光が赤外線センサに干渉</td><td>ToF・ステレオの使用</td></tr><tr><td><strong>遮蔽</strong></td><td>物体の裏側が見えない</td><td>複数視点からの計測</td></tr></tbody></table><h3 id="_3-2-画像処理の課題" tabindex="-1">3.2 画像処理の課題 <a class="header-anchor" href="#_3-2-画像処理の課題" aria-label="Permalink to &quot;3.2 画像処理の課題&quot;">​</a></h3><table tabindex="0"><thead><tr><th>課題</th><th>説明</th></tr></thead><tbody><tr><td><strong>照明条件</strong></td><td>明るさの変化で見え方が変わる</td></tr><tr><td><strong>テンプレートマッチング</strong></td><td>特徴照合の精度に限界がある</td></tr><tr><td><strong>計算コスト</strong></td><td>リアルタイム処理には高性能ハードが必要</td></tr></tbody></table><hr><h2 id="_4-応用事例" tabindex="-1">4. 応用事例 <a class="header-anchor" href="#_4-応用事例" aria-label="Permalink to &quot;4. 応用事例&quot;">​</a></h2><h3 id="_4-1-3d物体認識" tabindex="-1">4.1 3D物体認識 <a class="header-anchor" href="#_4-1-3d物体認識" aria-label="Permalink to &quot;4.1 3D物体認識&quot;">​</a></h3><p>対象物の表面までの距離を各点で計測し、<strong>3D形状を推定</strong>して物体を識別する技術。</p><p>把持計画（Grasp Planning）と組み合わせて、ロボットが物体を掴む動作の自動計画に利用されます。</p><h3 id="_4-2-slam-再掲" tabindex="-1">4.2 SLAM（再掲） <a class="header-anchor" href="#_4-2-slam-再掲" aria-label="Permalink to &quot;4.2 SLAM（再掲）&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">定義</p><p><strong>SLAM</strong>（Simultaneous Localization and Mapping）：距離センサや画像を用いて、<strong>自己位置推定</strong>と<strong>環境地図構築</strong>を同時に行う技術。</p></div><h3 id="_4-3-ハンドトラッキング" tabindex="-1">4.3 ハンドトラッキング <a class="header-anchor" href="#_4-3-ハンドトラッキング" aria-label="Permalink to &quot;4.3 ハンドトラッキング&quot;">​</a></h3><p>距離画像を用いて手の形状を追跡し、VR/MRなどのインタラクションに利用します。</p><h3 id="_4-4-自動運転" tabindex="-1">4.4 自動運転 <a class="header-anchor" href="#_4-4-自動運転" aria-label="Permalink to &quot;4.4 自動運転&quot;">​</a></h3><p>LiDAR やカメラの画像処理を組み合わせて、周辺環境を認識し自律走行を実現します。</p><hr><h2 id="📝-確認問題" tabindex="-1">📝 確認問題 <a class="header-anchor" href="#📝-確認問題" aria-label="Permalink to &quot;📝 確認問題&quot;">​</a></h2><h3 id="q1-rgb-dカメラの「d」は何を意味するか" tabindex="-1">Q1. RGB-Dカメラの「D」は何を意味するか？ <a class="header-anchor" href="#q1-rgb-dカメラの「d」は何を意味するか" aria-label="Permalink to &quot;Q1. RGB-Dカメラの「D」は何を意味するか？&quot;">​</a></h3><ul><li>[ ] A. Digital</li><li>[x] B. Depth（深度）</li><li>[ ] C. Direction</li><li>[ ] D. Display</li></ul><h3 id="q2-点群データとは" tabindex="-1">Q2. 点群データとは？ <a class="header-anchor" href="#q2-点群データとは" aria-label="Permalink to &quot;Q2. 点群データとは？&quot;">​</a></h3><ul><li>[ ] A. 2D画像のピクセル集合</li><li>[x] B. 各ピクセルに対応する3D座標データの集合</li><li>[ ] C. 音声データの時系列</li><li>[ ] D. センサの誤差データ</li></ul><h3 id="q3-構造化光方式の原理は" tabindex="-1">Q3. 構造化光方式の原理は？ <a class="header-anchor" href="#q3-構造化光方式の原理は" aria-label="Permalink to &quot;Q3. 構造化光方式の原理は？&quot;">​</a></h3><ul><li>[ ] A. 音波の反射を利用</li><li>[ ] B. 磁界の変化を検出</li><li>[x] C. 投影したパターンの歪みから距離を推定</li><li>[ ] D. 温度変化を検出</li></ul><h3 id="q4-画像計測で透明な物体の検出が困難な理由は" tabindex="-1">Q4. 画像計測で透明な物体の検出が困難な理由は？ <a class="header-anchor" href="#q4-画像計測で透明な物体の検出が困難な理由は" aria-label="Permalink to &quot;Q4. 画像計測で透明な物体の検出が困難な理由は？&quot;">​</a></h3><ul><li>[x] A. 光が透過して反射が弱いから</li><li>[ ] B. 温度が低いから</li><li>[ ] C. 磁性がないから</li><li>[ ] D. 音を反射しないから</li></ul><h3 id="q5-slamで同時に行う2つの処理は" tabindex="-1">Q5. SLAMで同時に行う2つの処理は？ <a class="header-anchor" href="#q5-slamで同時に行う2つの処理は" aria-label="Permalink to &quot;Q5. SLAMで同時に行う2つの処理は？&quot;">​</a></h3><ul><li>[ ] A. 撮影と録音</li><li>[x] B. 自己位置推定と地図構築</li><li>[ ] C. 圧縮と解凍</li><li>[ ] D. 暗号化と復号化</li></ul><hr><h2 id="📚-次週の予習" tabindex="-1">📚 次週の予習 <a class="header-anchor" href="#📚-次週の予習" aria-label="Permalink to &quot;📚 次週の予習&quot;">​</a></h2><ul><li><strong>第11週</strong>: 角度、回転方向、回転速度の計測原理</li><li>予習ポイント：ポテンショメータ、ロータリエンコーダの概念</li></ul>',32))])}const A=o(b,[["render",u]]);export{q as __pageData,A as default};
